const Web3 = require('web3');
const fs = require('fs');
const path = require('path');

class MEVBot {
  constructor(config) {
    this.web3 = new Web3(config.rpcUrl);
    this.account = this.web3.eth.accounts.privateKeyToAccount(config.privateKey);
    this.web3.eth.defaultAccount = this.account.address;
    this.gasPriceMultiplier = config.gasPriceMultiplier || 1.5;
    this.minProfit = config.minProfit || 1000000000000000000n; // 1 ETH
    this.contractAddresses = config.contractAddresses || [];
    this.whitelistedTokens = config.whitelistedTokens || [];
    this.mempoolCache = new Set();
    this.isRunning = false;
  }

  async validateTransaction(tx) {
    try {
      if (!tx.to || !tx.from) return false;
      if (!this.whitelistedTokens.includes(tx.to)) return false;
      if (this.contractAddresses.includes(tx.to)) return false;
      if (tx.value && BigInt(tx.value) > 0n) return false;
      return true;
    } catch (error) {
      return false;
    }
  }

  async getGasPrice() {
    const baseGasPrice = await this.web3.eth.getGasPrice();
    return Math.floor(baseGasPrice * this.gasPriceMultiplier);
  }

  async findArbitrageOpportunities() {
    try {
      const pendingTxs = await this.web3.eth.getPendingTransactions();
      const opportunities = [];

      for (const tx of pendingTxs) {
        if (this.mempoolCache.has(tx.hash)) continue;
        if (!(await this.validateTransaction(tx))) continue;

        const txReceipt = await this.web3.eth.getTransactionReceipt(tx.hash);
        if (txReceipt) continue;

        opportunities.push(tx);
      }

      return opportunities;
    } catch (error) {
      console.error('Error finding arbitrage opportunities:', error);
      return [];
    }
  }

  async executeArbitrage(tx) {
    try {
      const gasPrice = await this.getGasPrice();
      const estimatedGas = await this.web3.eth.estimateGas({
        from: this.account.address,
        to: tx.to,
        data: tx.input,
        value: tx.value || '0x0'
      });

      const transaction = {
        from: this.account.address,
        to: tx.to,
        data: tx.input,
        value: tx.value || '0x0',
        gas: estimatedGas,
        gasPrice: gasPrice
      };

      const signedTx = await this.account.signTransaction(transaction);
      const receipt = await this.web3.eth.sendSignedTransaction(signedTx.rawTransaction);
      
      this.mempoolCache.add(tx.hash);
      return receipt;
    } catch (error) {
      console.error('Error executing arbitrage:', error);
      return null;
    }
  }

  async start() {
    this.isRunning = true;
    console.log('MEV Bot started');
    
    while (this.isRunning) {
      try {
        const opportunities = await this.findArbitrageOpportunities();
        for (const tx of opportunities) {
          await this.executeArbitrage(tx);
        }
        await new Promise(resolve => setTimeout(resolve, 1000));
      } catch (error) {
        console.error('Bot error:', error);
      }
    }
  }

  stop() {
    this.isRunning = false;
    console.log('MEV Bot stopped');
  }
}

// Load configuration from environment
const config = {
  rpcUrl: process.env.RPC_URL || 'https://mainnet.infura.io/v3/YOUR_PROJECT_ID',
  privateKey: process.env.PRIVATE_KEY,
  gasPriceMultiplier: parseFloat(process.env.GAS_MULTIPLIER) || 1.5,
  minProfit: BigInt(process.env.MIN_PROFIT || '1000000000000000000'),
  contractAddresses: process.env.CONTRACT_ADDRESSES ? process.env.CONTRACT_ADDRESSES.split(',') : [],
  whitelistedTokens: process.env.WHITELISTED_TOKENS ? process.env.WHITELISTED_TOKENS.split(',') : []
};

// Validate configuration
if (!config.privateKey) {
  throw new Error('PRIVATE_KEY environment variable is required');
}

if (!config.rpcUrl) {
  throw new Error('RPC_URL environment variable is required');
}

const bot = new MEVBot(config);

// Start the bot
bot.start().catch(console.error);

// Graceful shutdown
process.on('SIGINT', () => {
  console.log('Shutting down bot...');
  bot.stop();
  process.exit(0);
});

module.exports = MEVBot;